import { Component, OnInit } from '@angular/core';
import { ApiService } from '../../services/api.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html'
})
export class DashboardComponent implements OnInit {
  public upcoming: any[] = [];
  public past: any[] = [];
  public cancelled: any[] = [];
  public message = '';
  public upgradeRequest = { source: '', destination: '' };

  constructor(private api: ApiService, public auth: AuthService) {}

  ngOnInit(): void {
    this.loadDashboard();
  }

  public loadDashboard(): void {
    this.api.getBookingDashboard().subscribe({
      next: (result: any) => {
        this.upcoming = result.upcoming || [];
        this.past = result.past || [];
        this.cancelled = result.cancelled || [];
      },
      error: () => {}
    });
  }

  public cancelBooking(booking: any): void {
    if (!confirm(`Cancel booking ${booking.bookingReference}? This action cannot be undone.`)) return;
    this.message = '';
    this.api.cancelBooking(booking.id).subscribe({
      next: () => {
        this.message = 'Booking cancelled and refund processed.';
        this.loadDashboard();
      },
      error: err => this.message = err.error?.message || err.error || err.statusText
    });
  }

  public requestOperatorUpgrade(): void {
    this.message = '';
    if (!this.upgradeRequest.source || !this.upgradeRequest.destination) {
      this.message = 'Please enter both source and destination.';
      return;
    }
    this.api.requestOperatorUpgrade(this.upgradeRequest).subscribe({
      next: () => {
        this.message = `Request submitted for ${this.upgradeRequest.source} → ${this.upgradeRequest.destination}. Await admin approval.`;
        this.upgradeRequest = { source: '', destination: '' };
      },
      error: err => this.message = typeof err.error === 'string' ? err.error : err.error?.message || err.statusText
    });
  }
}
<div class="card">
  <h2>My Dashboard</h2>
  <div class="card">
    <h3>Upcoming Journeys</h3>
    <div *ngIf="upcoming.length === 0">No upcoming bookings.</div>
    <div *ngFor="let booking of upcoming" class="card">
      <p><strong>Reference:</strong> {{ booking.bookingReference }}</p>
      <p><strong>Route:</strong> {{ booking.route?.source }} → {{ booking.route?.destination }}</p>
      <p><strong>Date:</strong> {{ booking.travelDate | date }}</p>
      <p><strong>Time:</strong> {{ booking.timing }}</p>
      <p><strong>Amount:</strong> {{ booking.totalAmount | currency:'INR':'symbol':'1.0-0' }}</p>
      <p><strong>Status:</strong> {{ booking.status }}</p>
      <button class="btn btn-danger btn-sm" (click)="cancelBooking(booking)">Cancel Booking</button>
    </div>
  </div>

  <div class="card">
    <h3>Past Journeys</h3>
    <div *ngIf="past.length === 0">No past journeys.</div>
    <div *ngFor="let booking of past" class="card">
      <p><strong>Reference:</strong> {{ booking.bookingReference }}</p>
      <p><strong>Route:</strong> {{ booking.route?.source }} → {{ booking.route?.destination }}</p>
      <p><strong>Date:</strong> {{ booking.travelDate | date }}</p>
      <p><strong>Amount:</strong> {{ booking.totalAmount | currency }}</p>
    </div>
  </div>

  <div class="card">
    <h3>Cancelled Journeys</h3>
    <div *ngIf="cancelled.length === 0">No cancelled journeys.</div>
    <div *ngFor="let booking of cancelled" class="card">
      <p><strong>Reference:</strong> {{ booking.bookingReference }}</p>
      <p><strong>Route:</strong> {{ booking.route?.source }} → {{ booking.route?.destination }}</p>
      <p><strong>Date:</strong> {{ booking.travelDate | date }}</p>
      <p><strong>Amount:</strong> {{ booking.totalAmount | currency }}</p>
      <p><strong>Status:</strong> {{ booking.status }}</p>
    </div>
  </div>
  <div class="card" *ngIf="!auth.hasRole('BusOperator') && !auth.hasRole('Admin')">
    <h3>Become a Bus Operator</h3>
    <p>Enter your boarding point and destination to apply for operator access.</p>
    <div class="form-grid" style="max-width:480px">
      <div class="form-group">
        <label>Boarding Point (Source) *</label>
        <input [(ngModel)]="upgradeRequest.source" name="opSource" placeholder="e.g. Chennai" />
      </div>
      <div class="form-group">
        <label>Destination *</label>
        <input [(ngModel)]="upgradeRequest.destination" name="opDest" placeholder="e.g. Coimbatore" />
      </div>
    </div>
    <button class="btn btn-primary" style="margin-top:12px" (click)="requestOperatorUpgrade()"
      [disabled]="!upgradeRequest.source || !upgradeRequest.destination">
      Submit Upgrade Request
    </button>
    <p *ngIf="message" style="margin-top:0.75rem; color: green">{{ message }}</p>
  </div>
</div>
